import pandas as pd
import matplotlib.pyplot as plt
import os

# ==========================================
# CONFIGURATION
# ==========================================
RESULTS_DIR = '/media/ajay/Backup_Plus1/datasets/coloradar/kitti/2_28_2021_outdoors_run7/results'
CSV_PATH = os.path.join(RESULTS_DIR, 'ablation_summary.csv')

def generate_detailed_plots():
    if not os.path.exists(CSV_PATH):
        print(f"Error: Could not find {CSV_PATH}. Make sure you ran sweep.py first!")
        return

    # Load the summary CSV generated by sweep.py
    df = pd.read_csv(CSV_PATH)

    # Filter out failures
    success_df = df[df["Status"] == "SUCCESS"].copy()
    
    # Separate numeric skip rates from "blind"
    numeric_df = success_df[success_df["Skip_Rate"] != "blind"].copy()
    numeric_df["Skip_Rate"] = pd.to_numeric(numeric_df["Skip_Rate"])

    # Setup the 2x3 subplot grid
    fig, axes = plt.subplots(2, 3, figsize=(18, 10))
    fig.suptitle('Odometry Degradation Analysis by Axis', fontsize=18, fontweight='bold')

    # Define the 6 metrics we want to plot
    metrics =[
        ('rmse_x', 'X Translation Error', 'RMSE (meters)'),
        ('rmse_y', 'Y Translation Error', 'RMSE (meters)'),
        ('rmse_z', 'Z Translation (Elevation) Error', 'RMSE (meters)'),
        ('rmse_roll', 'Roll Error', 'RMSE (degrees)'),
        ('rmse_pitch', 'Pitch Error', 'RMSE (degrees)'),
        ('rmse_yaw', 'Yaw Error', 'RMSE (degrees)')
    ]

    scenarios = df["Scenario"].unique()
    markers = ['o', 's', '^', 'd']
    colors = ['b', 'g', 'm', 'r']
    
    # Map scenarios to colors/markers for consistency
    style_map = {scen: (colors[i % len(colors)], markers[i % len(markers)]) for i, scen in enumerate(scenarios)}

    for idx, (metric, title, ylabel) in enumerate(metrics):
        row = idx // 3
        col = idx % 3
        ax = axes[row, col]

        for scenario in scenarios:
            color, marker = style_map[scenario]
            
            # 1. Plot the continuous line for numeric skip rates
            scenario_data = numeric_df[numeric_df["Scenario"] == scenario]
            if not scenario_data.empty:
                # Sort by skip rate just in case
                scenario_data = scenario_data.sort_values(by="Skip_Rate")
                ax.plot(scenario_data["Skip_Rate"], scenario_data[metric], 
                        marker=marker, color=color, linestyle='-', linewidth=2, label=scenario)

            # 2. Plot the "blind" mode as a distinct star on the far right
            blind_data = success_df[(success_df["Scenario"] == scenario) & (success_df["Skip_Rate"] == "blind")]
            if not blind_data.empty:
                # We place the blind star at x=2000 so it visually sits past the 1000 mark
                ax.scatter([2000], blind_data[metric], color=color, marker='*', s=200, zorder=5)

        # Formatting
        ax.set_xscale('log')
        ax.set_title(title, fontsize=14)
        ax.set_xlabel('Ground Truth Skip Rate (Log Scale)')
        ax.set_ylabel(ylabel)
        ax.grid(True, which="both", ls="--", alpha=0.5)
        
        # Only put the legend on the first plot to save space
        if idx == 0:
            ax.legend(loc='upper left', fontsize=10)

    # Add a global footnote explaining the stars
    plt.figtext(0.5, 0.02, 'Stars (*) represent "Blind" mode (No Ground Truth updates after initialization)', 
                ha='center', fontsize=12, style='italic')

    plt.tight_layout(rect=[0, 0.04, 1, 0.96]) # Adjust layout to fit suptitle and figtext
    
    # Save and Show
    plot_path = os.path.join(RESULTS_DIR, "ablation_plot_all_axes.png")
    plt.savefig(plot_path, dpi=300)
    print(f"Detailed axes plot saved to {plot_path}")
    plt.show()

if __name__ == "__main__":
    generate_detailed_plots()